#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 1000
#define MAXM 1000

int isStable(char reservoir[MAXN][MAXM], int N, int M) {
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (reservoir[i][j] == 'W') {
                if (i > 0 && reservoir[i - 1][j] == 'A') return 0;
                if (j > 0 && reservoir[i][j - 1] == 'A') return 0;
                if (j < M - 1 && reservoir[i][j + 1] == 'A') return 0;
            } else if (reservoir[i][j] == 'B') {
                if (i == N - 1 || reservoir[i + 1][j] == 'B' || reservoir[i + 1][j] == 'W') continue;
                return 0;
            }
        }
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char reservoir[N][MAXM];
        for (int i = 0; i < N; i++) {
            scanf(" %s", reservoir[i]);
        }
        if (isStable(reservoir, N, M)) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

