import java.util.Scanner;
public class Main {
    public static boolean isStable(char[][] reservoir) {
        int N = reservoir.length;
        int M = reservoir[0].length;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (reservoir[i][j] == 'W') {
                    if (i > 0 && reservoir[i - 1][j] == 'A') return false;
                    if (j > 0 && reservoir[i][j - 1] == 'A') return false;
                    if (j < M - 1 && reservoir[i][j + 1] == 'A') return false;
                } else if (reservoir[i][j] == 'B') {
                    if (i == N - 1 || reservoir[i + 1][j] == 'B' || reservoir[i + 1][j] == 'W') continue;
                    return false;
                }
            }
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            char[][] reservoir = new char[N][M];
            for (int i = 0; i < N; i++) {
                String row = scanner.next();
                reservoir[i] = row.toCharArray();
            }
            if (isStable(reservoir)) System.out.println("yes");
            else System.out.println("no");
        }
    }
}

